# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public async Task<bool> HandleTicketPurchase(int eventId, int quantity)
{
    using (var context = new EventDbContext())
    {
        // Get the event from the database
        var @event = await context.Events.FindAsync(eventId);

        // Check if the event exists
        if (@event == null)
        {
            return false;
        }

        // Check if there are enough seats available
        if (@event.AvailableSeats < quantity)
        {
            return false;
        }

        // Update the event inventory with a pessimistic lock
        @event.AvailableSeats -= quantity;

        // Mark the entity as modified
        context.Entry(@event).State = EntityState.Modified;

        // Save the changes to the database
        try
        {
            await context.SaveChangesAsync();
            return true;
        }
        catch (DbUpdateConcurrencyException)
        {
            // Handle concurrency conflicts and retry the purchase
            return false;
        }
    }
